import React, { useEffect, useState } from 'react';
import { adminAPI, categoriesAPI, productsAPI } from '../../api';
import styles from './AdminPage.module.css';

const EMPTY_PRODUCT_FORM = {
  name: '',
  description: '',
  details: '',
  price: '',
  imageUrl: '',
  categoryId: '',
  stock: 0,
  isNew: false,
  isDiscount: false,
  isPopular: false,
  isDayItem: false,
};

const EMPTY_CATEGORY_FORM = {
  name: '',
};

const EMPTY_MODAL_FORM = {
  triggerCategoryId: '',
  title: '',
  description: '',
  productId: '',
  isActive: true,
};

export default function AdminPage() {
  const [tab, setTab] = useState('products');

  const [loading, setLoading] = useState(true);

  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [modals, setModals] = useState([]);

  const [productForm, setProductForm] = useState(EMPTY_PRODUCT_FORM);
  const [categoryForm, setCategoryForm] = useState(EMPTY_CATEGORY_FORM);
  const [modalForm, setModalForm] = useState(EMPTY_MODAL_FORM);

  const [editProductId, setEditProductId] = useState(null);

  const [productMsg, setProductMsg] = useState('');
  const [categoryMsg, setCategoryMsg] = useState('');
  const [modalMsg, setModalMsg] = useState('');

  const flash = (setter, message, timeout = 2500) => {
    setter(message);
    window.setTimeout(() => setter(''), timeout);
  };

  const unwrapCategories = (data) => {
    if (Array.isArray(data)) return data;
    if (Array.isArray(data?.categories)) return data.categories;
    return [];
  };

  const unwrapProducts = (data) => {
    if (Array.isArray(data)) return data;
    if (Array.isArray(data?.products)) return data.products;
    return [];
  };

  const unwrapModals = (data) => {
    if (Array.isArray(data)) return data;
    if (Array.isArray(data?.modals)) return data.modals;
    return [];
  };

  const loadAll = async () => {
    setLoading(true);
    try {
      const [productsResp, categoriesResp, modalsResp] = await Promise.all([
        productsAPI.getAll({ limit: 200 }),
        categoriesAPI.getAdminAll(),
        adminAPI.getAdModals(),
      ]);

      const nextProducts = unwrapProducts(productsResp.data);
      const nextCategories = unwrapCategories(categoriesResp.data);
      const nextModals = unwrapModals(modalsResp.data);

      setProducts(nextProducts);
      setCategories(nextCategories);
      setModals(nextModals);

      // Подставляем дефолты в формы
      if (!productForm.categoryId && nextCategories.length > 0) {
        setProductForm((prev) => ({
          ...prev,
          categoryId: nextCategories[0].id,
        }));
      }

      if (!modalForm.triggerCategoryId && nextCategories.length > 0) {
        setModalForm((prev) => ({
          ...prev,
          triggerCategoryId: nextCategories[0].id,
        }));
      }

      if (!modalForm.productId && nextProducts.length > 0) {
        setModalForm((prev) => ({
          ...prev,
          productId: nextProducts[0].id,
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAll();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (categories.length > 0) {
      setProductForm((prev) =>
        prev.categoryId ? prev : { ...prev, categoryId: categories[0].id }
      );

      setModalForm((prev) =>
        prev.triggerCategoryId
          ? prev
          : { ...prev, triggerCategoryId: categories[0].id }
      );
    }
  }, [categories]);

  useEffect(() => {
    if (products.length > 0) {
      setModalForm((prev) =>
        prev.productId ? prev : { ...prev, productId: products[0].id }
      );
    }
  }, [products]);

  const handleProductChange = (e) => {
    const { name, value, type, checked } = e.target;
    setProductForm((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleCategoryChange = (e) => {
    setCategoryForm({ name: e.target.value });
  };

  const handleModalChange = (e) => {
    const { name, value, type, checked } = e.target;
    setModalForm((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();

    if (!productForm.categoryId) {
      flash(setProductMsg, 'Выберите категорию');
      return;
    }

    const payload = {
      name: productForm.name.trim(),
      description: productForm.description.trim(),
      details: productForm.details.trim(),
      price: Number(productForm.price),
      imageUrl: productForm.imageUrl.trim(),
      categoryId: productForm.categoryId,
      stock: Number(productForm.stock),
      isNew: Boolean(productForm.isNew),
      isDiscount: Boolean(productForm.isDiscount),
      isPopular: Boolean(productForm.isPopular),
      isDayItem: Boolean(productForm.isDayItem),
    };

    try {
      if (editProductId) {
        await adminAPI.updateProduct(editProductId, payload);
        flash(setProductMsg, 'Товар обновлён ✓');
      } else {
        await adminAPI.createProduct(payload);
        flash(setProductMsg, 'Товар добавлен ✓');
      }

      setProductForm(EMPTY_PRODUCT_FORM);
      setEditProductId(null);
      await loadAll();
    } catch (err) {
      flash(
        setProductMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось сохранить товар'}`
      );
    }
  };

  const handleEditProduct = (product) => {
    setEditProductId(product.id);
    setProductForm({
      name: product.name || '',
      description: product.description || '',
      details: product.details || '',
      price: product.price ?? '',
      imageUrl: product.imageUrl || product.image_url || '',
      categoryId: product.categoryId || product.category?.id || '',
      stock: product.stock ?? 0,
      isNew: Boolean(product.isNew ?? product.is_new),
      isDiscount: Boolean(product.isDiscount ?? product.is_discount),
      isPopular: Boolean(product.isPopular ?? product.is_popular),
      isDayItem: Boolean(product.isDayItem ?? product.is_day_item),
    });

    setTab('products');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteProduct = async (id) => {
    if (!window.confirm('Удалить товар?')) return;

    try {
      await adminAPI.deleteProduct(id);
      await loadAll();
      flash(setProductMsg, 'Товар удалён');
    } catch (err) {
      flash(
        setProductMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось удалить товар'}`
      );
    }
  };

  const handleCategorySubmit = async (e) => {
    e.preventDefault();

    const name = categoryForm.name.trim();
    if (!name) {
      flash(setCategoryMsg, 'Введите название категории');
      return;
    }

    try {
      await categoriesAPI.create({ name });
      setCategoryForm(EMPTY_CATEGORY_FORM);
      await loadAll();
      flash(setCategoryMsg, 'Категория добавлена ✓');
    } catch (err) {
      flash(
        setCategoryMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось создать категорию'}`
      );
    }
  };

  const handleDeleteCategory = async (id) => {
    if (!window.confirm('Удалить категорию? Если к ней привязаны товары, удаление может быть запрещено.'))
      return;

    try {
      await categoriesAPI.remove(id);
      await loadAll();
      flash(setCategoryMsg, 'Категория удалена');
    } catch (err) {
      flash(
        setCategoryMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось удалить категорию'}`
      );
    }
  };

  const handleModalSubmit = async (e) => {
    e.preventDefault();

    if (!modalForm.triggerCategoryId) {
      flash(setModalMsg, 'Выберите категорию-триггер');
      return;
    }

    if (!modalForm.productId) {
      flash(setModalMsg, 'Выберите товар');
      return;
    }

    const payload = {
      triggerCategoryId: modalForm.triggerCategoryId,
      title: modalForm.title.trim(),
      description: modalForm.description.trim(),
      productId: modalForm.productId,
      isActive: Boolean(modalForm.isActive),
    };

    try {
      await adminAPI.createAdModal(payload);
      setModalForm(EMPTY_MODAL_FORM);
      await loadAll();
      flash(setModalMsg, 'Попап создан ✓');
    } catch (err) {
      flash(
        setModalMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось создать попап'}`
      );
    }
  };

  const handleDeleteModal = async (id) => {
    if (!window.confirm('Удалить рекламный попап?')) return;

    try {
      await adminAPI.deleteAdModal(id);
      await loadAll();
      flash(setModalMsg, 'Попап удалён');
    } catch (err) {
      flash(
        setModalMsg,
        `Ошибка: ${err.response?.data?.error || 'не удалось удалить попап'}`
      );
    }
  };

  if (loading) {
    return (
      <div className={styles.loadingWrap}>
        <div className={styles.spinner} />
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className="container">
        {/* Шапка */}
        <div className={styles.adminHeader}>
          <div>
            <h1 className={styles.adminTitle}>👑 Админ-панель</h1>
            <p className={styles.adminSub}>
              Управление товарами, категориями и рекламой
            </p>
          </div>

          <div className={styles.stats}>
            <div className={styles.statCard}>
              <span className={styles.statNum}>{products.length}</span>
              <span className={styles.statLabel}>Товаров</span>
            </div>
            <div className={styles.statCard}>
              <span className={styles.statNum}>{categories.length}</span>
              <span className={styles.statLabel}>Категорий</span>
            </div>
            <div className={styles.statCard}>
              <span className={styles.statNum}>{modals.length}</span>
              <span className={styles.statLabel}>Попапов</span>
            </div>
          </div>
        </div>

        {/* Вкладки */}
        <div className={styles.tabs}>
          {[
            { key: 'products', label: '🛍️ Товары' },
            { key: 'categories', label: '📁 Категории' },
            { key: 'modals', label: '🎁 Реклама' },
          ].map((item) => (
            <button
              key={item.key}
              type="button"
              className={`${styles.tab} ${tab === item.key ? styles.activeTab : ''}`}
              onClick={() => setTab(item.key)}
            >
              {item.label}
            </button>
          ))}
        </div>

        {/* ─────────────────────────────
            ТОВАРЫ
        ────────────────────────────── */}
        {tab === 'products' && (
          <div className={styles.tabContent}>
            <div className={styles.formCard}>
              <h2 className={styles.formTitle}>
                {editProductId ? '✏️ Редактировать товар' : '➕ Добавить товар'}
              </h2>

              <form className={styles.productForm} onSubmit={handleProductSubmit}>
                <div className={styles.formGrid}>
                  <div className={styles.field}>
                    <label className={styles.label}>Название *</label>
                    <input
                      name="name"
                      className={styles.input}
                      value={productForm.name}
                      onChange={handleProductChange}
                      placeholder="Например: Вишнёвый торт"
                      required
                    />
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Цена (₽) *</label>
                    <input
                      name="price"
                      type="number"
                      min="0"
                      step="0.01"
                      className={styles.input}
                      value={productForm.price}
                      onChange={handleProductChange}
                      placeholder="0"
                      required
                    />
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Категория *</label>
                    <select
                      name="categoryId"
                      className={styles.input}
                      value={productForm.categoryId}
                      onChange={handleProductChange}
                      required
                    >
                      <option value="">— Выберите категорию —</option>
                      {categories.map((cat) => (
                        <option key={cat.id} value={cat.id}>
                          {cat.name}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Остаток</label>
                    <input
                      name="stock"
                      type="number"
                      min="0"
                      className={styles.input}
                      value={productForm.stock}
                      onChange={handleProductChange}
                    />
                  </div>
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Короткое описание</label>
                  <textarea
                    name="description"
                    className={`${styles.input} ${styles.textarea}`}
                    value={productForm.description}
                    onChange={handleProductChange}
                    placeholder="Короткое описание для карточки товара"
                  />
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Подробное описание</label>
                  <textarea
                    name="details"
                    className={`${styles.input} ${styles.textarea}`}
                    value={productForm.details}
                    onChange={handleProductChange}
                    placeholder="Подробное описание товара, состав, особенности, для чего подходит"
                  />
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>URL изображения</label>
                  <input
                    name="imageUrl"
                    className={styles.input}
                    value={productForm.imageUrl}
                    onChange={handleProductChange}
                    placeholder="https://..."
                  />
                </div>

                <div className={styles.flags}>
                  {[
                    { name: 'isNew', label: '✨ Новинка' },
                    { name: 'isDiscount', label: '💰 Скидка' },
                    { name: 'isPopular', label: '🔥 Популярный' },
                    { name: 'isDayItem', label: '⭐ Товар дня' },
                  ].map((flag) => (
                    <label key={flag.name} className={styles.checkboxLabel}>
                      <input
                        type="checkbox"
                        name={flag.name}
                        checked={Boolean(productForm[flag.name])}
                        onChange={handleProductChange}
                        className={styles.checkbox}
                      />
                      {flag.label}
                    </label>
                  ))}
                </div>

                {productMsg && (
                  <p
                    className={`${styles.msg} ${
                      productMsg.toLowerCase().includes('ошибка')
                        ? styles.msgError
                        : styles.msgOk
                    }`}
                  >
                    {productMsg}
                  </p>
                )}

                <div className={styles.formActions}>
                  <button type="submit" className="btn btn-cherry">
                    {editProductId ? 'Сохранить изменения' : 'Добавить товар'}
                  </button>

                  {editProductId && (
                    <button
                      type="button"
                      className="btn btn-ghost"
                      onClick={() => {
                        setEditProductId(null);
                        setProductForm(EMPTY_PRODUCT_FORM);
                      }}
                    >
                      Отмена
                    </button>
                  )}
                </div>
              </form>
            </div>

            <div className={styles.tableWrap}>
              <h2 className={styles.tableTitle}>Все товары ({products.length})</h2>

              <div className={styles.table}>
                <div className={styles.tableHead}>
                  <span>Товар</span>
                  <span>Категория</span>
                  <span>Цена</span>
                  <span>Остаток</span>
                  <span>Флаги</span>
                  <span>Действия</span>
                </div>

                {products.map((product) => (
                  <div key={product.id} className={styles.tableRow}>
                    <span className={styles.productNameBlock}>
                      <span className={styles.productName}>{product.name}</span>
                      <span className={styles.productDesc}>
                        {product.details || product.description || 'Без описания'}
                      </span>
                    </span>

                    <span className={styles.catCell}>
                      {product.category?.name || '—'}
                    </span>

                    <span className={styles.priceCell}>
                      {Number(product.price).toLocaleString('ru-RU')} ₽
                    </span>

                    <span className={styles.stockCell}>
                      <span className={product.stock <= 5 ? styles.lowStock : ''}>
                        {product.stock}
                      </span>
                    </span>

                    <span className={styles.flagsCell}>
                      {product.isNew && <span className="badge badge-new">New</span>}
                      {product.isPopular && (
                        <span className="badge badge-popular">Hot</span>
                      )}
                      {product.isDayItem && (
                        <span className="badge badge-day">Day</span>
                      )}
                      {product.isDiscount && (
                        <span className="badge badge-new">Sale</span>
                      )}
                    </span>

                    <span className={styles.actionsCell}>
                      <button
                        type="button"
                        className={`btn btn-outline btn-sm ${styles.editBtn}`}
                        onClick={() => handleEditProduct(product)}
                      >
                        Изменить
                      </button>

                      <button
                        type="button"
                        className={styles.deleteBtn}
                        onClick={() => handleDeleteProduct(product.id)}
                        title="Удалить"
                      >
                        🗑️
                      </button>
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ─────────────────────────────
            КАТЕГОРИИ
        ────────────────────────────── */}
        {tab === 'categories' && (
          <div className={styles.tabContent}>
            <div className={styles.formCard}>
              <h2 className={styles.formTitle}>➕ Добавить категорию</h2>

              <form className={styles.productForm} onSubmit={handleCategorySubmit}>
                <div className={styles.field}>
                  <label className={styles.label}>Название категории *</label>
                  <input
                    className={styles.input}
                    value={categoryForm.name}
                    onChange={handleCategoryChange}
                    placeholder="Например: Ягоды"
                    required
                  />
                </div>

                {categoryMsg && (
                  <p
                    className={`${styles.msg} ${
                      categoryMsg.toLowerCase().includes('ошибка')
                        ? styles.msgError
                        : styles.msgOk
                    }`}
                  >
                    {categoryMsg}
                  </p>
                )}

                <button type="submit" className="btn btn-cherry">
                  Создать категорию
                </button>
              </form>
            </div>

            <div className={styles.tableWrap}>
              <h2 className={styles.tableTitle}>Категории ({categories.length})</h2>

              <div className={styles.table}>
                <div className={styles.tableHead}>
                  <span>Название</span>
                  <span>Slug</span>
                  <span>Создано</span>
                  <span>Товаров</span>
                  <span>Статус</span>
                  <span>Действия</span>
                </div>

                {categories.map((cat) => {
                  const productCount = products.filter(
                    (p) => p.categoryId === cat.id
                  ).length;

                  return (
                    <div key={cat.id} className={styles.tableRow}>
                      <span className={styles.productNameBlock}>
                        <span className={styles.productName}>{cat.name}</span>
                        <span className={styles.productDesc}>
                          Категория для каталога
                        </span>
                      </span>

                      <span className={styles.catCell}>{cat.slug}</span>

                      <span className={styles.dateCell}>
                        {cat.createdAt
                          ? new Date(cat.createdAt).toLocaleDateString('ru-RU')
                          : '—'}
                      </span>

                      <span className={styles.stockCell}>{productCount}</span>

                      <span className={styles.flagsCell}>
                        <span className="badge badge-new">Active</span>
                      </span>

                      <span className={styles.actionsCell}>
                        <button
                          type="button"
                          className={styles.deleteBtn}
                          onClick={() => handleDeleteCategory(cat.id)}
                          title="Удалить категорию"
                        >
                          🗑️
                        </button>
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {/* ─────────────────────────────
            РЕКЛАМА
        ────────────────────────────── */}
        {tab === 'modals' && (
          <div className={styles.tabContent}>
            <div className={styles.formCard}>
              <h2 className={styles.formTitle}>➕ Создать рекламный попап</h2>

              <form className={styles.productForm} onSubmit={handleModalSubmit}>
                <div className={styles.formGrid}>
                  <div className={styles.field}>
                    <label className={styles.label}>Категория-триггер *</label>
                    <select
                      name="triggerCategoryId"
                      className={styles.input}
                      value={modalForm.triggerCategoryId}
                      onChange={handleModalChange}
                      required
                    >
                      <option value="">— Выберите категорию —</option>
                      {categories.map((cat) => (
                        <option key={cat.id} value={cat.id}>
                          {cat.name}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Товар для предложения *</label>
                    <select
                      name="productId"
                      className={styles.input}
                      value={modalForm.productId}
                      onChange={handleModalChange}
                      required
                    >
                      <option value="">— Выберите товар —</option>
                      {products.map((product) => (
                        <option key={product.id} value={product.id}>
                          {product.name}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Заголовок попапа *</label>
                  <input
                    name="title"
                    className={styles.input}
                    value={modalForm.title}
                    onChange={handleModalChange}
                    placeholder="Например: Дополните заказ десертом"
                    required
                  />
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Описание</label>
                  <textarea
                    name="description"
                    className={`${styles.input} ${styles.textarea}`}
                    value={modalForm.description}
                    onChange={handleModalChange}
                    placeholder="Короткий текст для рекламного окна"
                  />
                </div>

                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    name="isActive"
                    checked={Boolean(modalForm.isActive)}
                    onChange={handleModalChange}
                    className={styles.checkbox}
                  />
                  Попап активен
                </label>

                {modalMsg && (
                  <p
                    className={`${styles.msg} ${
                      modalMsg.toLowerCase().includes('ошибка')
                        ? styles.msgError
                        : styles.msgOk
                    }`}
                  >
                    {modalMsg}
                  </p>
                )}

                <button type="submit" className="btn btn-cherry">
                  Создать попап
                </button>
              </form>
            </div>

            <div className={styles.tableWrap}>
              <h2 className={styles.tableTitle}>Все попапы ({modals.length})</h2>

              <div className={styles.table}>
                <div className={styles.tableHead}>
                  <span>Название</span>
                  <span>Категория</span>
                  <span>Товар</span>
                  <span>Статус</span>
                  <span>Создан</span>
                  <span>Действия</span>
                </div>

                {modals.map((modal) => (
                  <div key={modal.id} className={styles.tableRow}>
                    <span className={styles.productNameBlock}>
                      <span className={styles.productName}>{modal.title}</span>
                      <span className={styles.productDesc}>
                        {modal.description || 'Без описания'}
                      </span>
                    </span>

                    <span className={styles.catCell}>
                      {modal.triggerCategory?.name || modal.triggerCategory?.slug || '—'}
                    </span>

                    <span className={styles.stockCell}>
                      {modal.product?.name || '—'}
                    </span>

                    <span className={styles.flagsCell}>
                      {modal.isActive ? (
                        <span className="badge badge-new">Active</span>
                      ) : (
                        <span className="badge badge-day">Disabled</span>
                      )}
                    </span>

                    <span className={styles.dateCell}>
                      {modal.createdAt
                        ? new Date(modal.createdAt).toLocaleDateString('ru-RU')
                        : '—'}
                    </span>

                    <span className={styles.actionsCell}>
                      <button
                        type="button"
                        className={styles.deleteBtn}
                        onClick={() => handleDeleteModal(modal.id)}
                        title="Удалить попап"
                      >
                        🗑️
                      </button>
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
